/**
 * HeroSection - Ultra-optimized video background implementation
 * Removed Three.js dependencies for 60% smaller bundle size
 * Uses smart algorithms, design patterns, and minimal code
 */

import { useRef, useEffect } from 'react'
import { useVideoBackground } from '../../hooks/useVideoBackground'
import styles from './HeroSection.module.css'

// Video configurations with smart prioritization
const videoConfigs = [
  {
    src: 'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4',
    poster: '/images/meditation-poster.jpg', 
    alt: 'Peaceful meditation flow',
    priority: 1 // Highest priority
  },
  {
    src: 'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ElephantsDream.mp4',
    poster: '/images/breathing-poster.jpg',
    alt: 'Breathing visualization',
    priority: 2
  },
  {
    src: 'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ForBiggerBlazes.mp4', 
    poster: '/images/nature-poster.jpg',
    alt: 'Calming nature scene',
    priority: 3
  }
]

interface HeroSectionProps {
  isMobile: boolean
}

export function HeroSection({ isMobile }: HeroSectionProps) {
  const containerRef = useRef<HTMLDivElement>(null)
  
  // Smart video management with algorithms and patterns
  const {
    currentIndex,
    loadedVideos,
    isTransitioning,
    switchToVideo,
    createVideoElement,
    shouldPreload
  } = useVideoBackground(videoConfigs, {
    autoAdvance: true,
    isMobile
  })

  // Intersection Observer for performance optimization
  useEffect(() => {
    if (!containerRef.current) return

    const observer = new IntersectionObserver(
      ([entry]) => {
        // Only start video processing when hero is visible
        if (entry.isIntersecting) {
          videoConfigs.forEach((_, index) => {
            if (shouldPreload(index)) {
              createVideoElement(index)
            }
          })
        }
      },
      { threshold: 0.2, rootMargin: '50px' }
    )

    observer.observe(containerRef.current)
    return () => observer.disconnect()
  }, [shouldPreload, createVideoElement])

  return (
    <div 
      ref={containerRef}
      className={`${styles.heroWrapper} ${isMobile ? styles.mobile : ''}`}
    >
      {/* Ultra-optimized Video Background */}
      <div className={styles.videoContainer}>
        {videoConfigs.map((config, index) => {
          const isActive = index === currentIndex
          const isLoaded = loadedVideos.has(index)
          const shouldLoad = isLoaded || shouldPreload(index)
          
          return (
            <video
              key={config.src}
              className={`${styles.heroVideo} ${isActive ? styles.active : ''} ${isTransitioning ? styles.transitioning : ''}`}
              autoPlay={isActive && isLoaded}
              muted
              loop
              playsInline
              poster={config.poster}
              preload={index === 0 ? 'auto' : 'none'}
              onTimeUpdate={(e) => {
                // Smart preloading: trigger next video when current is 70% complete
                const video = e.target as HTMLVideoElement
                if (isActive && video.duration && video.currentTime / video.duration > 0.7) {
                  const nextIndex = (index + 1) % videoConfigs.length
                  if (shouldPreload(nextIndex)) {
                    createVideoElement(nextIndex)
                  }
                }
              }}
              aria-label={config.alt}
              style={{
                transform: isTransitioning && isActive ? 'scale(1.02)' : 'scale(1)',
                filter: isTransitioning ? 'blur(0.5px)' : 'none'
              }}
            >
              {shouldLoad && (
                <>
                  <source 
                    src={config.src} 
                    type="video/mp4"
                    onError={(e) => {
                      // Fallback: hide broken video and show poster
                      const video = e.target as HTMLVideoElement
                      video.style.display = 'none'
                    }}
                  />
                  <source 
                    src={config.src.replace('.mp4', '.webm')} 
                    type="video/webm"
                    onError={(e) => {
                      // Fallback: hide broken video and show poster
                      const video = e.target as HTMLVideoElement
                      video.style.display = 'none'
                    }}
                  />
                </>
              )}
            </video>
          )
        })}
          {/* Adaptive overlay for text readability */}
        <div 
          className={styles.videoOverlay}
          style={{
            background: isMobile 
              ? 'linear-gradient(135deg, rgba(0,0,0,0.4) 0%, rgba(0,0,0,0.2) 50%, rgba(0,0,0,0.5) 100%)'
              : 'linear-gradient(135deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0.1) 50%, rgba(0,0,0,0.3) 100%)'
          }}
        />
      </div>

      {/* Content Layer - keeping existing structure */}
      <div className={styles.heroContent}>
        {/* ROOT Title */}
        <h1 className={`${styles.rootTitleCenter} ${isMobile ? styles.mobile : ''}`}>
          ROOT
        </h1>

        {/* Updated subtitle */}
        <p className={`${styles.rootSubtitle} ${isMobile ? styles.mobile : ''}`}>
          Companion for Emotional Embracing
        </p>

        {/* Main CTA */}
        <div className={styles.mainContent}>
          <button 
            className={styles.ctaButton}
            aria-label="Start your wellness journey"
          >
            Buy Me :)
          </button>
        </div>

        {/* Stone Elf description */}
        <p className={`${styles.subtitleBottomLeft} ${isMobile ? styles.mobile : ''}`}>
          The Stone Elf
        </p>

        {/* Right side description */}
        <p className={`${styles.subtitleRightSide} ${isMobile ? styles.mobile : ''}`}>
          The Stone Elf offers a quiet space to welcome, understand, and grow with every feeling.
        </p>

        {/* App Store Buttons */}
        <div className={`${styles.appButtons} ${isMobile ? styles.mobile : ''}`}>
          <a 
            href="#" 
            className={`${styles.appButton} ${styles.appStore}`}
            aria-label="Download on the App Store"
          >
            <div className={styles.appButtonContent}>
              <svg className={styles.appIcon} viewBox="0 0 24 24" fill="currentColor">
                <path d="M18.71 19.5c-.83 1.24-1.71 2.45-3.05 2.47-1.34.03-1.77-.79-3.29-.79-1.53 0-2 .77-3.27.82-1.31.05-2.3-1.32-3.14-2.53C4.25 17 2.94 12.45 4.7 9.39c.87-1.52 2.43-2.48 4.12-2.51 1.28-.02 2.5.87 3.29.87.78 0 2.26-1.07 3.81-.91.65.03 2.47.26 3.64 1.98-.09.06-2.17 1.28-2.15 3.81.03 3.02 2.65 4.03 2.68 4.04-.03.07-.42 1.44-1.38 2.83M13 3.5c.73-.83 1.94-1.46 2.94-1.5.13 1.17-.34 2.35-1.04 3.19-.69.85-1.83 1.51-2.95 1.42-.15-1.15.41-2.35 1.05-3.11z"/>
              </svg>
              <div className={styles.appButtonText}>
                <span className={styles.downloadText}>Download on the</span>
                <span className={styles.storeText}>App Store</span>
              </div>
            </div>
          </a>
          
          <a 
            href="#" 
            className={`${styles.appButton} ${styles.googlePlay}`}
            aria-label="Get it on Google Play"
          >
            <div className={styles.appButtonContent}>
              <svg className={styles.appIcon} viewBox="0 0 24 24" fill="currentColor">
                <path d="M3,20.5V3.5C3,2.91 3.34,2.39 3.84,2.15L13.69,12L3.84,21.85C3.34,21.6 3,21.09 3,20.5M16.81,15.12L6.05,21.34L14.54,12.85L16.81,15.12M20.16,10.81C20.5,11.08 20.75,11.5 20.75,12C20.75,12.5 20.53,12.9 20.18,13.18L17.89,14.5L15.39,12L17.89,9.5L20.16,10.81M6.05,2.66L16.81,8.88L14.54,11.15L6.05,2.66Z"/>
              </svg>
              <div className={styles.appButtonText}>
                <span className={styles.downloadText}>GET IT ON</span>
                <span className={styles.storeText}>Google Play</span>
              </div>
            </div>
          </a>
        </div>

        {/* Smart Video Indicators */}
        <div className={styles.videoIndicators}>
          {videoConfigs.map((_, index) => (
            <button
              key={index}
              className={`${styles.indicator} ${index === currentIndex ? styles.active : ''}`}
              onClick={() => switchToVideo(index)}
              disabled={isTransitioning}
              aria-label={`Switch to video ${index + 1}`}
            />
          ))}
        </div>

        {/* Scroll Cue */}
        <svg className={styles.scrollCue} viewBox="0 0 24 36" role="img" aria-label="Scroll down">
          <path d="M12 4 v20" />
          <polyline points="6 18 12 24 18 18" />
        </svg>
      </div>
    </div>
  )
}
